def compute_score() -> tuple[str, float]:
    import pptx
    from pptx import Presentation
    import os
    # Load original and modified presentations
    prs_orig = Presentation(original_ppt_path)
    prs_mod = Presentation(modified_ppt_path)

    def get_slide_by_number(prs, slide_number):
        # 1-based slide index
        for idx, slide in enumerate(prs.slides, start=1):
            if idx == slide_number:
                return slide
        return None

    slide_num = 10
    orig_slide = get_slide_by_number(prs_orig, slide_num)
    mod_slide = get_slide_by_number(prs_mod, slide_num)
    if orig_slide is None or mod_slide is None:
        return f"Slide {slide_num} not found in original or modified presentation.", 0.0

    def get_first_table(slide):
        for shape in slide.shapes:
            if shape.has_table:
                return shape.table
        return None
    orig_table = get_first_table(orig_slide)
    mod_table = get_first_table(mod_slide)
    if orig_table is None or mod_table is None:
        return "Table not found on slide 10 in original or modified presentation.", 0.0

    # Extract all rows (excluding header) from both tables
    def extract_table_rows(table):
        # Assume first row is header
        rows = []
        for i in range(1, table.rows.__len__()):
            row = [table.cell(i, j).text.strip().replace("≥", "").replace("\n", " ") for j in range(table.columns.__len__())]
            rows.append(row)
        return rows
    orig_rows = extract_table_rows(orig_table)
    mod_rows = extract_table_rows(mod_table)
    if len(orig_rows) != len(mod_rows):
        return "Row count mismatch after sorting.", 0.0
    # Check that modification is a permutation of original rows
    orig_set = set(tuple(r) for r in orig_rows)
    mod_set = set(tuple(r) for r in mod_rows)
    if orig_set != mod_set:
        return "Table rows changed beyond sorting.", 0.0
    # Check sorted ascending by first column
    try:
        # Try to cast to float, otherwise compare as string
        def key(row):
            try:
                return float(row[0])
            except:
                return row[0]
        sorted_mod = sorted(mod_rows, key=key)
        if mod_rows == sorted_mod:
            return "Table correctly sorted by first column ascending.", 1.0
        else:
            return "Table not sorted correctly by first column.", 0.0
    except Exception as e:
        return f"Error checking sort: {e}", 0.0

