    if orig_img_path is None or mod_img_path is None:
        raise ScreenshotsUnavailableError(
            "Slide 10 screenshot missing while verifying "
            "no_extraneous_slide_10_changes; flagging task for verification "
            f"retry (original={orig_img_path is not None}, "
            f"modified={mod_img_path is not None})."
        )
    import PIL.ImageChops, PIL.Image
    try:
        img1 = PIL.Image.open(orig_img_path).convert("RGB")
        img2 = PIL.Image.open(mod_img_path).convert("RGB")
        if img1.size == img2.size:
            # Differences are expected due to row reordering; the leaf is lenient.
            return "No extraneous visual changes detected on slide 10.", 1.0
        else:
            return "Slide 10 size changed unexpectedly.", 0.0
    except ScreenshotsUnavailableError:
        raise
    except Exception as e:
        return f"Error comparing slide 10 screenshots: {e}", 1.0

def compute_score() -> tuple[str, float]:
    # Check all diffs in ppt_diff to see if any slide except 10 was touched
    changed_slides = set()
    for slide in ppt_diff.added_slides + ppt_diff.removed_slides:
        changed_slides.add(getattr(slide, 'slide_number', None))
    for slide_pair in ppt_diff.modified_slides:
        changed_slides.add(getattr(slide_pair[0], 'slide_number', None))
    if any(slide_num != 10 for slide_num in changed_slides if slide_num is not None):
        return "Changes made outside slide 10.", 0.0
    # Also check animations/transitions
    for anim in ppt_diff.added_animations + ppt_diff.removed_animations:
        if getattr(anim, 'slide_id', None) is not None:
            # Could check slide number from id but assume only slide 10 allowed
            return "Animation changes detected outside slide 10.", 0.0
    for trans in ppt_diff.added_transitions + ppt_diff.removed_transitions:
        if getattr(trans, 'slide_id', None) is not None:
            return "Transition changes detected outside slide 10.", 0.0
    return "No changes detected outside slide 10.", 1.0
